INSERT INTO public.questions (id, exam_id, paper_id, subject_id, chapter_id, question_type, question_text, options, correct_answer, correct_answer_json, auto_gradable, source, is_active, version, source_meta, explanation)
VALUES
  ('social-worker-moex-07690', 'social-worker', 'social-worker-moex-099-7c9828ae', 'sub-social-worker-02', NULL, 'single_choice', '社會工作的三大傳統基本方法為個案工作、團體工作與社區工作，對於三大工作方法特性之比較，下列 敘述何者錯誤？', '["個案及團體工作之目標在改變個人行為，社區工作的目標則在實質解決社區問題，提升社區自治能力", "個案工作之動力為家庭動力，團體工作則為團體動力，社區工作則為社區動力", "個案工作之主要技術為支持、傾聽；團體工作為社會衝突、團體動力學；社區工作則為方案設計、會 議及動員", "個案、團體工作之對象為失功能或處於困難中之受助者；社區工作則為社區領袖、菁英、一般居民"]'::jsonb, 0, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:10:39+00:00", "source_pdf_sha1": "f2d4042a3d9b", "answer_pdf_sha1": null, "source_family": "moex-gov-tw", "moex": {"exam_code": "099150", "c": "902", "s": "100", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "社會工作", "year": "099", "exam_name": "099年律師、會計師、不動產估價師、專利師、民間之公證人、社會工作師考試", "original_question_number": 5, "answer_corrected": false, "flags": ["answer_missing"], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-07691', 'social-worker', 'social-worker-moex-099-7c9828ae', 'sub-social-worker-02', NULL, 'single_choice', '台灣老齡人口數自1990年以來快速增加，1993年達到總人口數7.1％的「高齡化社會」，於2009年老齡 人口數已占總人口的10.6％，以下有關人口高齡化相關指數定義，何者錯誤？', '["扶養比係指0-14歲人口與65歲以上人口總和除以15-64歲人口之比率", "扶老比係指65歲以上人口除以0-14歲人口之比率", "扶幼比係指0-14歲人口除以15-64歲人口之比率", "人口自然增加率係指出生人數減去死亡人數除以年中人口數之比率"]'::jsonb, 0, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:10:39+00:00", "source_pdf_sha1": "f2d4042a3d9b", "answer_pdf_sha1": null, "source_family": "moex-gov-tw", "moex": {"exam_code": "099150", "c": "902", "s": "100", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "社會工作", "year": "099", "exam_name": "099年律師、會計師、不動產估價師、專利師、民間之公證人、社會工作師考試", "original_question_number": 6, "answer_corrected": false, "flags": ["answer_missing"], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-07692', 'social-worker', 'social-worker-moex-099-7c9828ae', 'sub-social-worker-02', NULL, 'single_choice', '請問當家裡老人其日常生活活動功能量表評估為重度以上，且實際由家人照顧，未接受機構安置、居家 服務者，如其家庭經濟狀況在一定情況以下者，可申請下列那種經濟協助？', '["家庭生活補助", "老年照顧補助", "特別照顧津貼", "看護補助"]'::jsonb, 0, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:10:39+00:00", "source_pdf_sha1": "f2d4042a3d9b", "answer_pdf_sha1": null, "source_family": "moex-gov-tw", "moex": {"exam_code": "099150", "c": "902", "s": "100", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "社會工作", "year": "099", "exam_name": "099年律師、會計師、不動產估價師、專利師、民間之公證人、社會工作師考試", "original_question_number": 7, "answer_corrected": false, "flags": ["answer_missing"], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-07693', 'social-worker', 'social-worker-moex-099-7c9828ae', 'sub-social-worker-02', NULL, 'single_choice', '國民年金法於2008年10月正式施行之後，原對家庭經濟狀況在一定條件以下之65歲老年所提供之敬老 福利津貼，併入國民年金體系之下，成為下列那一種法定年金給付？', '["老年基礎年金", "老年基本保證年金", "老年附加年金", "敬老津貼年金"]'::jsonb, 0, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:10:39+00:00", "source_pdf_sha1": "f2d4042a3d9b", "answer_pdf_sha1": null, "source_family": "moex-gov-tw", "moex": {"exam_code": "099150", "c": "902", "s": "100", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "社會工作", "year": "099", "exam_name": "099年律師、會計師、不動產估價師、專利師、民間之公證人、社會工作師考試", "original_question_number": 8, "answer_corrected": false, "flags": ["answer_missing"], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-07694', 'social-worker', 'social-worker-moex-099-7c9828ae', 'sub-social-worker-02', NULL, 'single_choice', '關於兒童及少年保護通報及處理，請問當直轄市、縣（市）政府於知悉有應保護之兒童及少年之通報案 件，應立即指派社會工作人員進行調查，請問立即係指在多少時限之內？', '["至遲不得超過6小時", "至遲不得超過12小時", "至遲不得超過18小時", "至遲不得超過24小時"]'::jsonb, 0, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:10:39+00:00", "source_pdf_sha1": "f2d4042a3d9b", "answer_pdf_sha1": null, "source_family": "moex-gov-tw", "moex": {"exam_code": "099150", "c": "902", "s": "100", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "社會工作", "year": "099", "exam_name": "099年律師、會計師、不動產估價師、專利師、民間之公證人、社會工作師考試", "original_question_number": 9, "answer_corrected": false, "flags": ["answer_missing"], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-07695', 'social-worker', 'social-worker-moex-099-7c9828ae', 'sub-social-worker-02', NULL, 'single_choice', '關於兒童及少年保護之個案，在法院裁定繼續安置期間，直轄市、縣（市）主管機關最遲應於安置期滿 為多少時間完成延長安置必要性之評估？', '["7日", "10日", "15日", "30日"]'::jsonb, 0, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:10:39+00:00", "source_pdf_sha1": "f2d4042a3d9b", "answer_pdf_sha1": null, "source_family": "moex-gov-tw", "moex": {"exam_code": "099150", "c": "902", "s": "100", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "社會工作", "year": "099", "exam_name": "099年律師、會計師、不動產估價師、專利師、民間之公證人、社會工作師考試", "original_question_number": 10, "answer_corrected": false, "flags": ["answer_missing"], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-07696', 'social-worker', 'social-worker-moex-099-7c9828ae', 'sub-social-worker-02', NULL, 'single_choice', '有關特殊境遇家庭扶助項目中子女生活津貼之相關規定，下列敘述何者錯誤？', '["補助對象含子女及孫子女", "年齡為12歲以下者", "補助標準為每一名每月補助當年度最低工資之十分之一", "每年申請乙次，初次申請者，得隨時提出"]'::jsonb, 0, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:10:39+00:00", "source_pdf_sha1": "f2d4042a3d9b", "answer_pdf_sha1": null, "source_family": "moex-gov-tw", "moex": {"exam_code": "099150", "c": "902", "s": "100", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "社會工作", "year": "099", "exam_name": "099年律師、會計師、不動產估價師、專利師、民間之公證人、社會工作師考試", "original_question_number": 11, "answer_corrected": false, "flags": ["answer_missing"], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-07697', 'social-worker', 'social-worker-moex-099-7c9828ae', 'sub-social-worker-02', NULL, 'single_choice', '有關社會工作人員在身心障礙福利服務中的轉銜任務與角色，下列敘述何者錯誤？', '["轉銜的意義被定義為一套有系統的過程，協助服務對象由一個環境轉換到另一個環境", "轉銜服務必須與生涯發展同時並行，應是長期性，而非短期性", "轉銜計畫，需要跨專業的合作包括教育、心理、衛生、社會服務、職業輔導等，父母暫不加入", "以個案管理方式提供跨專業的服務，以外展的精神提供多元的資源"]'::jsonb, 0, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:10:39+00:00", "source_pdf_sha1": "f2d4042a3d9b", "answer_pdf_sha1": null, "source_family": "moex-gov-tw", "moex": {"exam_code": "099150", "c": "902", "s": "100", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "社會工作", "year": "099", "exam_name": "099年律師、會計師、不動產估價師、專利師、民間之公證人、社會工作師考試", "original_question_number": 12, "answer_corrected": false, "flags": ["answer_missing"], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-07698', 'social-worker', 'social-worker-moex-099-7c9828ae', 'sub-social-worker-02', NULL, 'single_choice', '社會工作師之行為必須遵守社會工作倫理守則之規定，請問在我國社會工作師倫理守則由何單位訂定？', '["內政部", "縣市政府", "當地社會工作師公會", "全國社會工作師公會聯合會"]'::jsonb, 0, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:10:39+00:00", "source_pdf_sha1": "f2d4042a3d9b", "answer_pdf_sha1": null, "source_family": "moex-gov-tw", "moex": {"exam_code": "099150", "c": "902", "s": "100", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "社會工作", "year": "099", "exam_name": "099年律師、會計師、不動產估價師、專利師、民間之公證人、社會工作師考試", "original_question_number": 13, "answer_corrected": false, "flags": ["answer_missing"], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-07699', 'social-worker', 'social-worker-moex-099-7c9828ae', 'sub-social-worker-02', NULL, 'single_choice', '社會工作師應保守業務之秘密，關於案主隱私權之相關規範，下列敘述何者錯誤？', '["案主聲請查閱個案社會工作紀錄時，社會工作師不得拒絕", "案主縱已死亡，社會工作師仍須重視其隱私權", "當社會工作師評估案主有自殺危險時，必要時不受保密的限制", "當社會工作師負有法律規定相關報告責任時，不受保密的限制"]'::jsonb, 0, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:10:39+00:00", "source_pdf_sha1": "f2d4042a3d9b", "answer_pdf_sha1": null, "source_family": "moex-gov-tw", "moex": {"exam_code": "099150", "c": "902", "s": "100", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "社會工作", "year": "099", "exam_name": "099年律師、會計師、不動產估價師、專利師、民間之公證人、社會工作師考試", "original_question_number": 14, "answer_corrected": false, "flags": ["answer_missing"], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL)
